class Solution:
    def longestPalindrome(self, s):
        n = len(s)
        best = ''
        for i in range(n):
            for j in range(i, n):
                sub = s[i:j + 1]
                if len(sub) > len(best) and sub == sub[::-1]:
                    best = sub
        return best

